[
  {
    "file": "internal/terraform/context_apply.go",
    "line": 150,
    "severity": "critical",
    "description": "Hook return values are ignored for PreApplyImport and PostApplyImport calls. The Hook interface defines these methods to return (HookAction, error), where HookActionHalt signals that processing should stop. However, the code at lines 150-155 calls these hooks but ignores their return values entirely. If a hook returns HookActionHalt, the apply process should halt, but currently it continues. This breaks the hook mechanism for controlling import operations during apply.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -150,8 +150,20 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts
 		for _, h := range c.hooks {
 			// In future, we may need to call PostApplyImport separately elsewhere in the apply
 			// operation. For now, though, we'll call Pre and Post hooks together.
-			h.PreApplyImport(hookResourceID, *rc.Importing)
-			h.PostApplyImport(hookResourceID, *rc.Importing)
+			action, err := h.PreApplyImport(hookResourceID, *rc.Importing)
+			if err != nil {
+				diags = diags.Append(tfdiags.Sourceless(tfdiags.Error, "Hook error", fmt.Sprintf("Hook failed during import: %s", err.Error())))
+			}
+			if action == HookActionHalt {
+				break
+			}
+			action, err = h.PostApplyImport(hookResourceID, *rc.Importing)
+			if err != nil {
+				diags = diags.Append(tfdiags.Sourceless(tfdiags.Error, "Hook error", fmt.Sprintf("Hook failed during import: %s", err.Error())))
+			}
+			if action == HookActionHalt {
+				break
+			}
 		}
 	}
 	}
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 201,
    "severity": "critical",
    "description": "Data integrity bug: When an input variable is declared as non-ephemeral but receives a value marked as ephemeral, the code appends an error diagnostic but still returns the marked value (line 222). The ephemeral mark is not removed or unset. This violates data integrity - an ephemeral value should never escape into a non-ephemeral variable context. The mark should either be removed or an unknown value should be returned to prevent ephemeral data from leaking.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -213,6 +213,10 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *I
 			Severity:  hcl.DiagError,
 			Summary:   "Ephemeral value not allowed",
 			Detail:    "This input variable is not declared as accepting a ephemeral values, so it cannot be set to a result derived from an ephemeral value.",
 			Subject:   subject.Ptr(),
 		})
+		// Return a placeholder unknown value to avoid producing redundant
+		// downstream errors and to prevent ephemeral data from leaking.
+		return cty.UnknownVal(cfg.Type), diags
 	}
 	}

"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 491,
    "severity": "medium",
    "description": "Copy-paste error in error message text. When a variable validation error message contains ephemeral values, the code appends a diagnostic with correct text ("Error message refers to ephemeral values") but then sets the errorMessage variable to "The error message included a sensitive value, so it will not be displayed." This message incorrectly says 'sensitive' instead of 'ephemeral', causing users to see confusing error messages.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -488,7 +488,7 @@ func evalVariableValidation(validation *configs.CheckRule, hclCtx *hcl.EvalCon
 			Expression:  validation.ErrorMessage,
 			EvalContext: hclCtx,
 		})
-		errorMessage = "The error message included a sensitive value, so it will not be displayed."
+		errorMessage = "The error message included an ephemeral value, so it will not be displayed."
 	} else {
 		errorMessage = strings.TrimSpace(errorValue.AsString())
 	}
"
  }
]

